# ai_router.py - Shadow/canary traffic router for strangler migration
import asyncio
import logging
import random
from dataclasses import dataclass
from enum import Enum
from typing import Any, Optional

import anthropic

logger = logging.getLogger(__name__)

class MigrationPhase(Enum):
    SHADOW = "shadow"      # new system runs but responses discarded
    CANARY = "canary"      # new system serves traffic_pct% of requests
    FULL = "full"          # new system serves 100%
    ROLLBACK = "rollback"  # all traffic to legacy

@dataclass
class RouterConfig:
    phase: MigrationPhase
    traffic_pct: float  # 0.0-1.0, used in CANARY phase
    log_divergences: bool = True
    fallback_on_error: bool = True

class StranglerRouter:
    def __init__(self, legacy_system, new_system, config: RouterConfig, divergence_logger):
        self.legacy = legacy_system
        self.new = new_system
        self.config = config
        self.div_logger = divergence_logger

    async def route(self, request: dict) -> Any:
        phase = self.config.phase

        if phase == MigrationPhase.FULL:
            return await self._call_new(request)

        if phase == MigrationPhase.ROLLBACK:
            return await self.legacy.handle(request)

        # Get legacy response (always authoritative in shadow/canary)
        legacy_response = await self.legacy.handle(request)

        if phase == MigrationPhase.SHADOW:
            # Fire-and-forget: call new system but don't use its response
            asyncio.create_task(self._shadow_compare(request, legacy_response))
            return legacy_response

        if phase == MigrationPhase.CANARY:
            if random.random() < self.config.traffic_pct:
                # Send this request to the new system
                new_response = await self._call_new(request, fallback=legacy_response)
                if self.config.log_divergences and new_response != legacy_response:
                    await self.div_logger.log(request, legacy_response, new_response)
                return new_response
            return legacy_response

    async def _shadow_compare(self, request: dict, legacy_resp: Any):
        """Run new system in shadow mode; log divergences for analysis."""
        try:
            new_resp = await self.new.handle(request)
            if self.config.log_divergences and new_resp != legacy_resp:
                await self.div_logger.log(request, legacy_resp, new_resp, mode="shadow")
        except Exception as e:
            logger.error(f"Shadow call failed: {e}")

    async def _call_new(self, request: dict, fallback: Optional[Any] = None) -> Any:
        """Call new system with optional fallback on error."""
        try:
            return await self.new.handle(request)
        except Exception as e:
            logger.error(f"New system error: {e}")
            if self.config.fallback_on_error and fallback is not None:
                logger.info("Falling back to legacy system")
                return fallback
            raise
